255	int EEPTPU_SA::eep_tpu_start_work(unsigned long addr)
256	{
257	    int ret;
258	
259	    if (bin_type == 1)
260	    {
261	        ret = eepreg_write(0x00000050, hwbase0 & 0xFFFFFFFF);  if (ret < 0) return ret;
262	        ret = eepreg_write(0x00000054, hwbase1 & 0xFFFFFFFF);  if (ret < 0) return ret;
263	    }
264	    else if (bin_type == 2)
265	    {
266	        ret = eepreg_write(0x00000050, hwbase0 & 0xFFFFFFFF);  if (ret < 0) return ret;     // par
267	        ret = eepreg_write(0x00000054, hwbase1 & 0xFFFFFFFF);  if (ret < 0) return ret;     // in
268	        ret = eepreg_write(0x00000058, hwbase2 & 0xFFFFFFFF);  if (ret < 0) return ret;     // tmp
269	        ret = eepreg_write(0x0000005c, hwbase3 & 0xFFFFFFFF);  if (ret < 0) return ret;     // out
270	    }
271	    ret = eepreg_write(0x00000030, addr);       if (ret < 0) return ret;
272	    ret = eepreg_write(0x00000034, 0x00000011); if (ret < 0) return ret;
273	
274	    /*
275	    unsigned int rval = 0;
276	    eepreg_read(0x50, &rval);  printf("Read ret 0x50: 0x%08x\r\n", rval);
277	    eepreg_read(0x54, &rval);  printf("Read ret 0x54: 0x%08x\r\n", rval);
278	    eepreg_read(0x30, &rval);  printf("Read ret 0x30: 0x%08x\r\n", rval);
279	    eepreg_read(0x34, &rval);  printf("Read ret 0x34: 0x%08x\r\n", rval);
280	    */
281	
282	    return 0;
283	}
