363	// read forward result from memory, convert it to ncnn mat format.
364	int EEPTPU_SA::read_forward_result(vector< ncnn::Mat >& outputs)
365	{
366	    int ret = -1;
367	    for (unsigned int i = 0; i < addr_out.size(); i++)
368	    {
369	        ncnn::Mat out;
370	        printf("read output[%d]: addr 0x%08x, shape: %d,%d,%d\n", i, addr_out[i].hwaddr, addr_out[i].shape[1], addr_out[i].shape[2], addr_out[i].shape[3]);
371	        unsigned int epmat_size = epmat_get_size(addr_out[i].shape[1], addr_out[i].shape[2], addr_out[i].shape[3]);
372	        printf("epmat_size = 0x%x(%d)\n", epmat_size, epmat_size);
373	        unsigned char* epmat = (unsigned char*) malloc (epmat_size);
374	        //unsigned  char epmat[64000];
375	        if (epmat == NULL) { return eeperr_Malloc; }
376	        memset(epmat, 0, epmat_size);
377	
378	        ret = eepif.mem_read(addr_out[i].hwaddr, epmat, epmat_size);
379	        if (ret < 0) return ret;
380	
381	        out = epmat2nmat(addr_out[i].shape[1], addr_out[i].shape[2], addr_out[i].shape[3], epmat, addr_out[i].exp);
382	        outputs.push_back(out);
383	        free(epmat);
384	    }
385	
386	    return 0;
387	}
